  1→/**
  2→ * Unified two-phase scoring engine for JobEngine.
  3→ *
  4→ * Phase 1 — Algorithmic (fast, free, deterministic):
  5→ *   Title match: 30%, Salary: 15%, Location: 20%, Recency: 15%, Seniority: 10%, Industry: 10%
  6→ *   If Phase 1 < 50 → discard immediately (no AI cost)
  7→ *
  8→ * Phase 2 — AI Semantic (Sonnet via inference-helper.ts):
  9→ *   Must-have match: 60%, Nice-to-have: 15%, Culture fit: 10%, Compensation fit: 15%
 10→ *   Only runs for listings that passed Phase 1 (>= 50%)
 11→ *   Final score = Phase 2 score
 12→ *
 13→ * Score routing:
 14→ *   80+  → tailored queue (or dream company regardless of score)
 15→ *   60-79 → auto-apply queue
 16→ *   <60  → discard
 17→ *   blacklisted → always discard
 18→ */
 19→
 20→import { existsSync, readFileSync } from "fs";
 21→import { join } from "path";
 22→import type {
 23→  AlgorithmicScoreBreakdown,
 24→  ScoreTier,
 25→  CompanyTier,
 26→} from "./types.ts";
 27→
 28→// =============================================================================
 29→// SCORING INPUT TYPE
 30→// =============================================================================
 31→
 32→export interface ScoringInput {
 33→  title: string;
 34→  company: string;
 35→  location: string;
 36→  salary_min_estimate: number | null;
 37→  posting_age_hours: number;
 38→  description_snippet: string;
 39→}
 40→
 41→export interface ScanCriteriaForScoring {
 42→  role_queries: string[];
 43→  location: {
 44→    cities: string[];
 45→    remote: boolean;
 46→    hybrid: boolean;
 47→  };
 48→  salary: {
 49→    min: number;
 50→    non_tech_floor?: number | null;
 51→  };
 52→  recency: {
 53→    max_age_days: number;
 54→  };
 55→  seniority: string[];
 56→  industry_keywords: string[];
 57→}
 58→
 59→// Seniority keyword mappings for title analysis
 60→const SENIORITY_KEYWORD_MAP: Record<string, string[]> = {
 61→  junior: ["junior", "jr", "entry", "associate", "intern", "i "],
 62→  mid: ["mid", "intermediate", "ii "],
 63→  senior: ["senior", "sr", "iii"],
 64→  lead: ["lead", "tech lead"],
 65→  staff: ["staff"],
 66→  principal: ["principal"],
 67→  distinguished: ["distinguished"],
 68→  architect: ["architect"],
 69→  director: ["director"],
 70→  vp: ["vp ", "vice president"],
 71→};
 72→
 73→export interface ScoringWeights {
 74→  title_match: number;
 75→  salary_match: number;
 76→  location_match: number;
 77→  recency_match: number;
 78→  seniority_match: number;
 79→  industry_match: number;
 80→}
 81→
 82→const DEFAULT_WEIGHTS: ScoringWeights = {
 83→  title_match: 30,
 84→  salary_match: 15,
 85→  location_match: 20,
 86→  recency_match: 15,
 87→  seniority_match: 10,
 88→  industry_match: 10,
 89→};
 90→
 91→function loadWeights(): ScoringWeights {
 92→  try {
 93→    const configPath = join(import.meta.dir, "../../State/scoring-config.json");
 94→    if (existsSync(configPath)) {
 95→      const config = JSON.parse(readFileSync(configPath, "utf-8")) as { weights?: Partial<ScoringWeights> };
 96→      if (config.weights) return { ...DEFAULT_WEIGHTS, ...config.weights };
 97→    }
 98→  } catch { /* Fall through to defaults */ }
 99→  return { ...DEFAULT_WEIGHTS };
100→}
101→
102→// Scoring weights (must sum to 100) — loaded once at import time, may be overridden by scoring-config.json
103→let WEIGHTS: ScoringWeights = loadWeights();
104→export { WEIGHTS, DEFAULT_WEIGHTS };
105→
106→// =============================================================================
107→// PHASE 1: ALGORITHMIC SCORING
108→// =============================================================================
109→
110→/**
111→ * Compute the Phase 1 algorithmic score (0-100).
112→ * Deterministic, zero inference cost.
113→ */
114→export function computeAlgorithmicScore(
115→  listing: ScoringInput,
116→  criteria: ScanCriteriaForScoring
117→): AlgorithmicScoreBreakdown {
118→  const title = listing.title.toLowerCase();
119→  const location = listing.location.toLowerCase();
120→  const descAndTitle = `${title} ${listing.description_snippet.toLowerCase()}`;
121→  const maxAgeHours = criteria.recency.max_age_days * 24;
122→
123→  // ── Title match (30%) ─────────────────────────────────────────────────────
124→  let titleMatchScore = 0;
125→  const roleQueries = criteria.role_queries.map((q) => q.toLowerCase());
126→
127→  let titleMatched = false;
128→  for (const query of roleQueries) {
129→    if (title.includes(query)) {
130→      titleMatched = true;
131→      break;
132→    }
133→  }
134→
135→  if (titleMatched) {
136→    titleMatchScore = WEIGHTS.title_match;
137→  }
138→
139→  // Exclusion penalty: internships, staff augmentation, etc.
140→  const exclusions = ["intern", "internship", "contractor only", "staffing agency", "temp-to-hire"];
141→  for (const exclusion of exclusions) {
142→    if (title.includes(exclusion)) {
143→      titleMatchScore = Math.max(0, titleMatchScore - WEIGHTS.title_match);
144→      break;
145→    }
146→  }
147→
148→  // ── Salary match (15%) ────────────────────────────────────────────────────
149→  let salaryMatchScore = 0;
150→  const salaryMin = listing.salary_min_estimate;
151→
152→  if (salaryMin === null || salaryMin === undefined) {
153→    // Many remote/tech jobs don't list salary — give partial credit (60%)
154→    salaryMatchScore = Math.round(WEIGHTS.salary_match * 0.6);
155→  } else if (salaryMin >= criteria.salary.min) {
156→    salaryMatchScore = WEIGHTS.salary_match;
157→  } else if (salaryMin >= criteria.salary.min * 0.85) {
158→    // Within 15% of minimum — partial credit (50%)
159→    salaryMatchScore = Math.round(WEIGHTS.salary_match * 0.5);
160→  }
161→  // Below 85% of minimum: 0 (hard filter candidate)
162→
163→  // ── Location match (20%) ──────────────────────────────────────────────────
164→  let locationMatchScore = 0;
165→  const isRemote =
166→    location.includes("remote") ||
167→    location.includes("anywhere") ||
168→    location.includes("distributed") ||
169→    location.includes("work from home");
170→  const isHybrid = location.includes("hybrid");
171→
172→  if (isRemote && criteria.location.remote) {
173→    locationMatchScore = WEIGHTS.location_match;
174→  } else if (isHybrid && criteria.location.hybrid) {
175→    locationMatchScore = Math.round(WEIGHTS.location_match * 0.8);
176→  } else {
177→    // Check configured cities
178→    for (const city of criteria.location.cities) {
179→      if (location.includes(city.toLowerCase())) {
180→        locationMatchScore = WEIGHTS.location_match;
181→        break;
182→      }
183→    }
184→    // Partial: if no city match but location is USA and remote preference
185→    if (locationMatchScore === 0 && criteria.location.remote) {
186→      const usaKeywords = ["usa", "united states", "us only", "nationwide"];
187→      for (const kw of usaKeywords) {
188→        if (location.includes(kw)) {
189→          locationMatchScore = Math.round(WEIGHTS.location_match * 0.5);
190→          break;
191→        }
192→      }
193→    }
194→  }
195→
196→  // ── Recency match (15%) ───────────────────────────────────────────────────
197→  let recencyMatchScore = 0;
198→  const ageHours = listing.posting_age_hours;
199→
200→  if (ageHours <= maxAgeHours) {
201→    recencyMatchScore = WEIGHTS.recency_match;
202→  } else if (ageHours <= maxAgeHours * 1.5) {
203→    recencyMatchScore = Math.round(WEIGHTS.recency_match * 0.5);
204→  }
205→  // Older than 1.5x maxAge: 0
206→
207→  // ── Seniority match (10%) ─────────────────────────────────────────────────
208→  let seniorityMatchScore = 0;
209→
210→  if (criteria.seniority.length === 0) {
211→    // No seniority filter = full credit
212→    seniorityMatchScore = WEIGHTS.seniority_match;
213→  } else {
214→    const targetLevels = criteria.seniority.map((s) => s.toLowerCase());
215→    for (const level of targetLevels) {
216→      const keywords = SENIORITY_KEYWORD_MAP[level] ?? [level];
217→      if (keywords.some((kw) => title.includes(kw))) {
218→        seniorityMatchScore = WEIGHTS.seniority_match;
219→        break;
220→      }
221→    }
222→  }
223→
224→  // ── Industry match (10%) ──────────────────────────────────────────────────
225→  let industryMatchScore = 0;
226→
227→  if (criteria.industry_keywords.length === 0) {
228→    industryMatchScore = WEIGHTS.industry_match;
229→  } else {
230→    const industryKeywords = criteria.industry_keywords.map((k) => k.toLowerCase());
231→    if (industryKeywords.some((kw) => descAndTitle.includes(kw))) {
232→      industryMatchScore = WEIGHTS.industry_match;
233→    }
234→  }
235→
236→  // ── Total ─────────────────────────────────────────────────────────────────
237→  const total = Math.max(
238→    0,
239→    Math.min(
240→      100,
241→      titleMatchScore +
242→      salaryMatchScore +
243→      locationMatchScore +
244→      recencyMatchScore +
245→      seniorityMatchScore +
246→      industryMatchScore
247→    )
248→  );
249→
250→  return {
251→    title_match: titleMatchScore,
252→    salary_match: salaryMatchScore,
253→    location_match: locationMatchScore,
254→    recency_match: recencyMatchScore,
255→    seniority_match: seniorityMatchScore,
256→    industry_match: industryMatchScore,
257→    total,
258→  };
259→}
260→
261→// =============================================================================
262→// SCORE ROUTING
263→// =============================================================================
264→
265→/**
266→ * Route a listing to the correct tier based on final score and company tier.
267→ *
268→ * Rules:
269→ *   - blacklisted → always discard
270→ *   - dream company → always tailored (regardless of score)
271→ *   - score >= 80 → tailored
272→ *   - score 70-79 → apply (raised from 60 — scores below 70 produced zero value)
273→ *   - score < 70 → discard
274→ */
275→export function routeByScore(score: number, companyTier: CompanyTier): ScoreTier {
276→  // Hard rules first
277→  if (companyTier === "blacklisted") return "discard";
278→  if (companyTier === "dream") return "tailored";
279→
280→  // Score-based routing
281→  if (score >= 80) return "tailored";
282→  if (score >= 70) return "apply";
283→  return "discard";
284→}
285→
286→// =============================================================================
287→// TITLE QUALITY GATES (Auto-Apply)
288→// =============================================================================
289→
290→/**
291→ * Hard title blocklist — reject titles that are clearly mismatched roles.
292→ * Returns the matched blocklist term, or null if the title passes.
293→ */
294→const TITLE_BLOCKLIST: string[] = [
295→  "data engineer",
296→  "engineering manager",
297→  "program manager",
298→  "product manager",
299→  "devops",
300→  "sre",
301→  "qa ",
302→  "quality assurance",
303→  "test engineer",
304→  "recruiter",
305→  "sales",
306→  "marketing",
307→  "rf engineer",
308→  "prompt specialist",
309→  "solutions architect",
310→  "intern",
311→  "associate",
312→  "junior",
313→  "consultant",
314→];
315→
316→/**
317→ * Exception patterns — if a blocklisted term matches but one of these
318→ * also matches, the title is NOT blocked (e.g. "Software Engineer, AI/ML").
319→ */
320→const TITLE_BLOCKLIST_EXCEPTIONS: string[] = [
321→  "ai", "ml", "machine learn", "data scien", "deep learn", "nlp", "llm",
322→];
323→
324→/**
325→ * Check if a job title should be blocked from auto-apply.
326→ * Returns the matched blocklist term, or null if the title passes.
327→ *
328→ * Special handling for "software engineer" — only blocked if it lacks
329→ * AI/ML qualifiers (plain "Software Engineer" is not a target role).
330→ */
331→export function checkTitleBlocklist(title: string): string | null {
332→  const lower = title.toLowerCase();
333→
334→  // Special case: "software engineer" without AI/ML qualifier
335→  if (
336→    (lower.includes("software engineer") || lower.includes("software developer")) &&
337→    !TITLE_BLOCKLIST_EXCEPTIONS.some((ex) => lower.includes(ex))
338→  ) {
339→    return "software engineer (no AI/ML qualifier)";
340→  }
341→
342→  for (const blocked of TITLE_BLOCKLIST) {
343→    if (lower.includes(blocked)) {
344→      // Check exceptions — if the title also contains an AI/ML term, allow it
345→      if (TITLE_BLOCKLIST_EXCEPTIONS.some((ex) => lower.includes(ex))) {
346→        return null;
347→      }
348→      return blocked;
349→    }
350→  }
351→
352→  return null;
353→}
354→
355→/**
356→ * Positive title requirement for auto-apply tier.
357→ * The title MUST contain at least one of these terms.
358→ * Returns true if the title passes the positive match.
359→ */
360→const POSITIVE_TITLE_TERMS: string[] = [
361→  "data scien",
362→  "machine learn",
363→  "ml ",
364→  "ai ",
365→  "artificial intel",
366→  "deep learn",
367→  "nlp",
368→  "llm",
369→  "rag",
370→  "applied scien",
371→];
372→
373→export function passesTitlePositiveMatch(title: string): boolean {
374→  const lower = title.toLowerCase();
375→  return POSITIVE_TITLE_TERMS.some((term) => lower.includes(term));
376→}
377→
378→// =============================================================================
379→// COMPANY TIER RESOLUTION
380→// =============================================================================
381→
382→/**
383→ * Resolve the company tier by checking against configured lists.
384→ * Case-insensitive partial match (e.g. "Meta" matches "Meta Platforms").
385→ */
386→export function resolveCompanyTier(
387→  companyName: string,
388→  dreamCompanies: string[],
389→  targetCompanies: string[],
390→  watchlistCompanies: string[],
391→  blacklistedCompanies: string[]
392→): CompanyTier {
393→  const name = companyName.toLowerCase();
394→
395→  const matchesList = (list: string[]): boolean =>
396→    list.some((item) => {
397→      const itemLower = item.toLowerCase();
398→      return name.includes(itemLower) || itemLower.includes(name);
399→    });
400→
401→  if (matchesList(blacklistedCompanies)) return "blacklisted";
402→  if (matchesList(dreamCompanies)) return "dream";
403→  if (matchesList(targetCompanies)) return "target";
404→  if (matchesList(watchlistCompanies)) return "watchlist";
405→  return "unknown";
406→}
407→
408→// =============================================================================
409→// PHASE 1 GATE
410→// =============================================================================
411→
412→/** Minimum Phase 1 score to proceed to Phase 2 AI scoring */
413→export const PHASE1_AI_GATE = 50;
414→
415→/**
416→ * Returns true if the Phase 1 score is high enough to warrant AI scoring.
417→ */
418→export function passesPhase1Gate(algorithmicScore: number): boolean {
419→  return algorithmicScore >= PHASE1_AI_GATE;
420→}
