import { describe, expect, test } from "bun:test";
import { routeByScore } from "./scoring.ts";

describe("routeByScore", () => {
  test("score 69 with unknown company returns discard", () => {
    expect(routeByScore(69, "unknown")).toBe("discard");
  });

  test("score 70 with unknown company returns apply", () => {
    expect(routeByScore(70, "unknown")).toBe("apply");
  });

  test("score 79 with unknown company returns apply", () => {
    expect(routeByScore(79, "unknown")).toBe("apply");
  });

  test("score 80 with unknown company returns tailored", () => {
    expect(routeByScore(80, "unknown")).toBe("tailored");
  });

  test("score 30 with dream company returns tailored (dream override)", () => {
    expect(routeByScore(30, "dream")).toBe("tailored");
  });

  test("score 95 with blacklisted company returns discard (blacklist override)", () => {
    expect(routeByScore(95, "blacklisted")).toBe("discard");
  });
});

